import React, { useState, useEffect } from 'react';
import api from '../../services/api';
import Toast from '../common/Toast';
import Loader from '../common/Loader';

interface Sector {
  id: number;
  name: string;
  description: string;
}

interface Question {
  id: number;
  sectorId: number;
  type: 'radio' | 'checkbox' | 'text' | 'textarea' | 'rating';
  text: string;
  options: string[] | null;
  required: boolean;
  order: number;
  isActive: boolean;
  createdAt?: string;
  updatedAt?: string;
}

const QuestionEditor: React.FC = () => {
  const [sectors, setSectors] = useState<Sector[]>([]);
  const [selectedSector, setSelectedSector] = useState<number | null>(null);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [showToast, setShowToast] = useState(false);
  const [toastMessage, setToastMessage] = useState('');
  const [toastType, setToastType] = useState<'success' | 'error'>('success');
  
  // Form state
  const [formData, setFormData] = useState({
    type: 'text' as Question['type'],
    text: '',
    options: [] as string[],
    required: false,
    order: 0,
    isActive: true
  });
  
  const [optionInput, setOptionInput] = useState('');

  // Get auth token from localStorage
  const getAuthToken = () => {
    const token = localStorage.getItem('token');
    return token;
  };

  useEffect(() => {
    fetchSectors();
  }, []);

  useEffect(() => {
    if (selectedSector) {
      fetchQuestions();
    }
  }, [selectedSector]);

  const fetchSectors = async () => {
    try {
      const response = await api.get('/api/sectors');
      let data = response.data.data || response.data;
      if (!Array.isArray(data)) {
        data = [];
      }
      setSectors(data);
      if (data.length > 0) {
        setSelectedSector(data[0].id);
      }
    } catch (err) {
      console.error('Error fetching sectors:', err);
      showMessage('Failed to load sectors', 'error');
    }
  };

  const fetchQuestions = async () => {
    if (!selectedSector) return;
    setLoading(true);
    try {
      // ✅ GET questions by sector
      const response = await api.get(`/api/questions/sector/${selectedSector}`);
      let data = response.data.data || response.data;
      if (!Array.isArray(data)) {
        data = [];
      }
      setQuestions(data);
      console.log('✅ Questions loaded:', data);
    } catch (err) {
      console.error('Error fetching questions:', err);
      showMessage('Failed to load questions', 'error');
    } finally {
      setLoading(false);
    }
  };

  const showMessage = (message: string, type: 'success' | 'error') => {
    setToastMessage(message);
    setToastType(type);
    setShowToast(true);
    setTimeout(() => setShowToast(false), 3000);
  };

  const handleAddOption = () => {
    if (optionInput.trim()) {
      setFormData({
        ...formData,
        options: [...formData.options, optionInput.trim()]
      });
      setOptionInput('');
    }
  };

  const handleRemoveOption = (index: number) => {
    setFormData({
      ...formData,
      options: formData.options.filter((_, i) => i !== index)
    });
  };

  const resetForm = () => {
    setFormData({
      type: 'text',
      text: '',
      options: [],
      required: false,
      order: questions.length,
      isActive: true
    });
    setEditingId(null);
    setOptionInput('');
  };

  const handleSaveQuestion = async () => {
    if (!selectedSector) {
      showMessage('Please select a sector', 'error');
      return;
    }
    
    if (!formData.text.trim()) {
      showMessage('Please enter question text', 'error');
      return;
    }
    
    // Validate options for radio/checkbox
    if ((formData.type === 'radio' || formData.type === 'checkbox') && formData.options.length === 0) {
      showMessage('Please add at least one option for radio/checkbox questions', 'error');
      return;
    }
    
    setSubmitting(true);
    
    const questionData = {
      sectorId: selectedSector,
      type: formData.type,
      text: formData.text,
      options: formData.options.length > 0 ? formData.options : null,
      required: formData.required,
      order: formData.order,
      isActive: formData.isActive
    };
    
    console.log('📤 Sending question data:', questionData);
    
    try {
      let response;
      if (editingId) {
        // ✅ UPDATE: PUT to /api/questions/:id
        response = await api.put(`/api/questions/${editingId}`, questionData);
        showMessage('Question updated successfully!', 'success');
        console.log('✅ Question updated:', response.data);
      } else {
        // ✅ CREATE: POST to /api/questions
        response = await api.post('/api/questions', questionData);
        showMessage('Question created successfully!', 'success');
        console.log('✅ Question created:', response.data);
      }
      resetForm();
      fetchQuestions();
    } catch (err: any) {
      console.error('❌ Error saving question:', err);
      console.error('Response:', err.response?.data);
      
      const errorMsg = err.response?.data?.error || err.response?.data?.message || 'Failed to save question';
      showMessage(errorMsg, 'error');
    } finally {
      setSubmitting(false);
    }
  };

  const handleEdit = (question: Question) => {
    setEditingId(question.id);
    setFormData({
      type: question.type,
      text: question.text,
      options: question.options || [],
      required: question.required,
      order: question.order,
      isActive: question.isActive
    });
  };

  const handleDelete = async (id: number) => {
    if (!window.confirm('Are you sure you want to delete this question?')) return;
    
    try {
      // ✅ DELETE: DELETE to /api/questions/:id
      await api.delete(`/api/questions/${id}`);
      showMessage('Question deleted successfully!', 'success');
      fetchQuestions();
    } catch (err) {
      console.error('Error deleting question:', err);
      showMessage('Failed to delete question', 'error');
    }
  };

  const handleToggleStatus = async (question: Question) => {
    try {
      // ✅ TOGGLE: PATCH to /api/questions/:id/toggle
      await api.patch(`/api/questions/${question.id}/toggle`);
      showMessage(`Question ${question.isActive ? 'deactivated' : 'activated'} successfully!`, 'success');
      fetchQuestions();
    } catch (err) {
      console.error('Error toggling question status:', err);
      showMessage('Failed to update question status', 'error');
    }
  };

  const getQuestionTypeLabel = (type: string) => {
    const labels: Record<string, string> = {
      radio: '🔘 Radio Button',
      checkbox: '☑️ Checkbox',
      text: '📝 Short Text',
      textarea: '📄 Long Text',
      rating: '⭐ Rating'
    };
    return labels[type] || type;
  };

  if (loading && questions.length === 0) {
    return <Loader fullScreen text="Loading questions..." />;
  }

  return (
    <div style={styles.container}>
      <h2 style={styles.title}>📝 Question Editor</h2>
      <p style={styles.subtitle}>Manage questions for each sector</p>

      {showToast && (
        <Toast message={toastMessage} type={toastType} onClose={() => setShowToast(false)} />
      )}

      {/* Sector Selector */}
      <div style={styles.sectorSelector}>
        <label style={styles.label}>Select Sector:</label>
        <select
          value={selectedSector || ''}
          onChange={(e) => setSelectedSector(parseInt(e.target.value))}
          style={styles.select}
        >
          {sectors.map(sector => (
            <option key={sector.id} value={sector.id}>{sector.name}</option>
          ))}
        </select>
      </div>

      {/* Question Form */}
      <div style={styles.formCard}>
        <h3>{editingId ? '✏️ Edit Question' : '➕ Add New Question'}</h3>
        
        <div style={styles.formGroup}>
          <label style={styles.label}>Question Type:</label>
          <select
            value={formData.type}
            onChange={(e) => setFormData({ ...formData, type: e.target.value as Question['type'] })}
            style={styles.select}
          >
            <option value="text">📝 Short Text</option>
            <option value="textarea">📄 Long Text</option>
            <option value="radio">🔘 Radio Button</option>
            <option value="checkbox">☑️ Checkbox</option>
            <option value="rating">⭐ Rating (1-5)</option>
          </select>
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Question Text:</label>
          <textarea
            value={formData.text}
            onChange={(e) => setFormData({ ...formData, text: e.target.value })}
            style={styles.textarea}
            rows={3}
            placeholder="Enter your question here..."
          />
        </div>

        {/* Options for Radio/Checkbox */}
        {(formData.type === 'radio' || formData.type === 'checkbox') && (
          <div style={styles.formGroup}>
            <label style={styles.label}>Options:</label>
            <div style={styles.optionsInput}>
              <input
                type="text"
                value={optionInput}
                onChange={(e) => setOptionInput(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && handleAddOption()}
                placeholder="Enter option and press Enter"
                style={styles.input}
              />
              <button onClick={handleAddOption} style={styles.addBtn}>Add Option</button>
            </div>
            <div style={styles.optionsList}>
              {formData.options.map((opt, idx) => (
                <span key={idx} style={styles.optionTag}>
                  {opt}
                  <button onClick={() => handleRemoveOption(idx)} style={styles.removeOption}>×</button>
                </span>
              ))}
            </div>
          </div>
        )}

        <div style={styles.formGroup}>
          <label style={styles.checkboxLabel}>
            <input
              type="checkbox"
              checked={formData.required}
              onChange={(e) => setFormData({ ...formData, required: e.target.checked })}
            />
            Required question
          </label>
        </div>

        <div style={styles.formActions}>
          <button onClick={handleSaveQuestion} disabled={submitting} style={styles.saveBtn}>
            {submitting ? 'Saving...' : editingId ? 'Update Question' : 'Add Question'}
          </button>
          {editingId && (
            <button onClick={resetForm} style={styles.cancelBtn}>
              Cancel Edit
            </button>
          )}
        </div>
      </div>

      {/* Questions List */}
      <div style={styles.listCard}>
        <h3>📋 Questions for {sectors.find(s => s.id === selectedSector)?.name || 'Selected Sector'}</h3>
        {questions.length === 0 ? (
          <p style={styles.emptyState}>No questions yet. Add your first question above.</p>
        ) : (
          <div style={styles.questionsList}>
            {questions.map((q, idx) => (
              <div key={q.id} style={{...styles.questionItem, opacity: q.isActive ? 1 : 0.5}}>
                <div style={styles.questionHeader}>
                  <span style={styles.questionNumber}>{idx + 1}.</span>
                  <span style={styles.questionType}>{getQuestionTypeLabel(q.type)}</span>
                  <span style={q.required ? styles.requiredBadge : styles.optionalBadge}>
                    {q.required ? 'Required' : 'Optional'}
                  </span>
                  <span style={q.isActive ? styles.activeBadge : styles.inactiveBadge}>
                    {q.isActive ? 'Active' : 'Inactive'}
                  </span>
                </div>
                <div style={styles.questionText}>{q.text}</div>
                {q.options && q.options.length > 0 && (
                  <div style={styles.questionOptions}>
                    <strong>Options:</strong> {q.options.join(', ')}
                  </div>
                )}
                <div style={styles.questionActions}>
                  <button onClick={() => handleEdit(q)} style={styles.editBtn}>✏️ Edit</button>
                  <button onClick={() => handleToggleStatus(q)} style={styles.toggleBtn}>
                    {q.isActive ? '🔴 Deactivate' : '🟢 Activate'}
                  </button>
                  <button onClick={() => handleDelete(q.id)} style={styles.deleteBtn}>🗑️ Delete</button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

const styles: { [key: string]: React.CSSProperties } = {
  container: {
    maxWidth: '1000px',
    margin: '2rem auto',
